import React from "react";
import "./App.sass";


function Todo({ todo, index, markDone, removeTodo }) {
  return (
    <div
      className="todo"
    >
      <span style={{ textDecoration: todo.isDone ? "line-through" : "" }}>{todo.text}</span>
      <button className="btn-done" onClick={() => markDone(index)}>✓</button>
      <button className="btn-delete" onClick={() => removeTodo(index)}>X</button>
    </div>
  );
}

function FormTodo({ addTodo }) {
  const [value, setValue] = React.useState("");

  const handleSubmit = e => {
    e.preventDefault();
    if (!value) return;
    addTodo(value);
    setValue("");
  };

  return (
    <form onSubmit={handleSubmit}> 
      <b>Add Todo</b>
      <input type="text" className="input" value={value} onChange={e => setValue(e.target.value)} placeholder="Add new todo" />
    <button variant="primary mb-3" type="submit">
      Submit
    </button>
  </form>
  );
}

function App() {
  const [todos, setTodos] = React.useState([
    {
      text: "Sample Todo",
      isDone: false
    }
  ]);

  const addTodo = text => {
    const newTodos = [...todos, { text }];
    setTodos(newTodos);
  };

  const markTodo = index => {
    const newTodos = [...todos];
    newTodos[index].isDone = true;
    setTodos(newTodos);
  };

  const removeTodo = index => {
    const newTodos = [...todos];
    newTodos.splice(index, 1);
    setTodos(newTodos);
  };

  return (
    <div className="app">
      <div className="container">
        <h1 className="text-center mb-4">Todo List</h1>
        <FormTodo addTodo={addTodo} />
        <div className="content">
          {todos.map((todo, index) => (
            <div>
              <Card.Body>
                <Todo
                key={index}
                index={index}
                todo={todo}
                markTodo={markTodo}
                removeTodo={removeTodo}
                />
              </Card.Body>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default App;
